   181→
   182→/* Masthead */
   183→.masthead { text-align: center; padding-bottom: 40px; margin-bottom: 48px; border-bottom: 1px solid var(--divider); }
   184→.masthead .pub { font-family: var(--sans); font-size: 0.75rem; letter-spacing: 0.25em; text-transform: uppercase; color: var(--text-light); margin-bottom: 32px; }
