   187→.masthead .hero-stat { font-family: var(--sans); font-size: 0.85rem; letter-spacing: 0.08em; text-transform: uppercase; color: var(--accent); background: linear-gradient(135deg,#faf6ed,#f0e6d0); border: 2px solid var(--divider); padding: 14px 32px; margin: 20px auto 16px; max-width: 580px; line-height: 1.6; }
