   193→
   194→/* Headings */
   195→h1 { font-family: var(--sans); font-size: 1.7rem; font-weight: 700; color: var(--accent); margin-top: 48px; margin-bottom: 20px; padding-bottom: 10px; border-bottom: 2px solid var(--accent); line-height: 1.2; }
