   202→
   203→/* Inline citations */
   204→.cite { font-family: var(--sans); font-size: 0.65rem; font-weight: 700; color: var(--accent-light); vertical-align: super; line-height: 0; margin: 0 1px; }
   205→
   206→/* Abstract / ELI5 */
   207→.abstract { background: var(--bg-alt); border-left: 3px solid var(--accent); padding: 24px 28px; margin: 40px 0; }
